import { createSlice, PayloadAction } from '@reduxjs/toolkit';

interface ErpSupplyState {
  loading: boolean;
}

const erpSupplySlice = createSlice({
  name: 'erpSupply',
  initialState: {
    loading: false,
  } as ErpSupplyState,
  reducers: {
    setLoading(state, { payload }: PayloadAction<boolean>) {
      state.loading = payload;
    },
  },
});

export const { setLoading } = erpSupplySlice.actions;
export default erpSupplySlice.reducer;
